'use client'

import { useEffect, useState } from "react";

export default function SleepPage() {
  const [bedTime, setBedTime] = useState("");
  const [wakeUpTime, setWakeUpTime] = useState("");
  const [isOhirune, setIsOhirune] = useState(false);
  const [sleepLogs, setSleepLogs] = useState<any[]>([]);

  // // ローカルストレージ読み込み
  // useEffect(() => {
  //   const saved = localStorage.getItem('sleepRecords');
  //   if(saved) {
  //     setSleepLogs(JSON.parse(saved));
  //   }
  // }, []);

  // // ローカルストレージ保存
  // useEffect(() => {
  //   localStorage.setItem("sleepRecords", JSON.stringify(sleepLogs))
  // }, [sleepLogs]);

  // 睡眠時間の計算
  const calcSleepMinutes = (start: string, end:string) => {
    const [startHour, startMinute] = start.split(":").map(Number);
    const [endHour, endMinute] = end.split(":").map(Number);

    const startTotal = startHour * 60 + startMinute;
    let endTotal = endHour * 60 + endMinute;

    // 日付またぎ対応
    if (endTotal < startTotal) {
      endTotal += 24 * 60;
    }

    return endTotal - startTotal;
  };

  // 睡眠時間表示フォーマット処理
  const formatMinutes = (minutes: number) => {
    const hour = Math.floor(minutes / 60);
    const minute = minutes % 60;
    return `${hour}時間${minute}分`;
  };
  
  // 記録ボタンが押下された時
  const addRecords = () => {
    if(!bedTime || !wakeUpTime) return;

    const newRecord = {
      bedTime,
      wakeUpTime,
      sleepType: isOhirune ? "ohirune" : "night",
    };

    setSleepLogs([...sleepLogs, newRecord]);
    setBedTime("");
    setWakeUpTime("");
    setIsOhirune(false);
  };

  // 削除
  const deleteRecord = (indexToDelete: number) => {
    const newRecords = sleepLogs.filter((_, index) => index !== indexToDelete);
    setSleepLogs(newRecords);
  };

  // 睡眠の合計値の計算
  const totalMinutes = sleepLogs.reduce((total, sleepLog) => {
    return total + calcSleepMinutes(sleepLog.bedTime, sleepLog.wakeUpTime);
  }, 0);

  return (
    <div>

      <h1>👶🌙💤娘の睡眠記録👶🌙💤</h1>

      <div>
        <label>就寝時間</label>
        <input 
        type="time" 
        value={bedTime} 
        onChange={(e) => setBedTime(e.target.value)}
        />
      </div>

      <div>
        <label>起床時間</label>
        <input 
        type="time"
        value={wakeUpTime}
        onChange={(e) => setWakeUpTime(e.target.value)}
        />
      </div>

      <div>
        <label>お昼寝</label>
        <input 
        type="checkbox"
        checked={isOhirune}
        onChange={(e) => setIsOhirune(e.target.checked)}
        />
      </div>

      <button onClick={addRecords}>記録する</button>

      <h2>記録一覧</h2>
      {sleepLogs.map((sleepLog, index) => {
          const sleepMinutes = calcSleepMinutes(
            sleepLog.bedTime,
            sleepLog.wakeUpTime
          );

          return(
              <div key={index}>
                  {sleepLog.sleepType === "ohirune" ? "お昼寝" : "夜の睡眠"}　
                  {sleepLog.bedTime} → {sleepLog.wakeUpTime}
                  （{formatMinutes(sleepMinutes)}）
                  <button 
                    onClick={() => deleteRecord(index)}
                    style={{ marginLeft: "10px" }}
                    >削除</button>
              </div>
          );
      })}
      
      {sleepLogs.length > 0 && (
        <div>
          <h3>合計値</h3>
          <div>{formatMinutes(totalMinutes)}</div>
        </div>
      )}

    </div>
  );
}